class Employee:
    def __init__(self, employee_id, employee_name, manager_id):
        self.employee_id = employee_id
        self.employee_name = employee_name
        self.manager_id = manager_id
        self.subordinates = []

def build_hierarchy(employees):
    employee_dict = {emp.employee_id: emp for emp in employees}
    root = None

    for emp in employees:
        if emp.manager_id is None:
            root = emp
        else:
            employee_dict[emp.manager_id].subordinates.append(emp)

    return root, employee_dict

def calculate_levels(employee, level, levels):
    levels[employee.employee_id] = level
    for subordinate in employee.subordinates:
        calculate_levels(subordinate, level + 1, levels)

def count_subordinates(employee):
    count = len(employee.subordinates)
    for subordinate in employee.subordinates:
        count += count_subordinates(subordinate)
    return count

def calculate_subordinate_counts(employee, subordinate_counts):
    subordinate_counts[employee.employee_id] = count_subordinates(employee)
    for subordinate in employee.subordinates:
        calculate_subordinate_counts(subordinate, subordinate_counts)

def build_manager_chain(employee, manager_chain, chain):
    if employee.manager_id is None:
        manager_chain[employee.employee_id] = chain
    else:
        manager_chain[employee.employee_id] = chain + [employee.manager_id]
        build_manager_chain(employee_dict[employee.manager_id], manager_chain, manager_chain[employee.employee_id])

