def analyze_hierarchy(employees):
    from collections import defaultdict

    # Parse the employee data
    employee_dict = {}
    for emp in employees:
        employee_dict[emp['employee_id']] = {
            'name': emp['employee_name'],
            'manager_id': emp['manager_id'],
            'subordinates': []
        }

    # Build the subordinate relationships
    for emp in employees:
        if emp['manager_id'] is not None:
            employee_dict[emp['manager_id']]['subordinates'].append(emp['employee_id'])

    # 1. Hierarchy Levels
    def calculate_levels(emp_id, level):
        levels[emp_id] = level
        for sub_id in employee_dict[emp_id]['subordinates']:
            calculate_levels(sub_id, level + 1)

    levels = {}
    for emp_id in employee_dict:
        if employee_dict[emp_id]['manager_id'] is None:  # CEO
            calculate_levels(emp_id, 1)

    # 2. Subordinate Count
    def count_subordinates(emp_id):
        count = len(employee_dict[emp_id]['subordinates'])
        for sub_id in employee_dict[emp_id]['subordinates']:
            count += count_subordinates(sub_id)
        subordinate_counts[emp_id] = count
        return count

    subordinate_counts = {}
    for emp_id in employee_dict:
        count_subordinates(emp_id)

    # 3. Manager Chain
    def build_manager_chain(emp_id):
        if employee_dict[emp_id]['manager_id'] is None:
            return None
        manager_chain = build_manager_chain(employee_dict[emp_id]['manager_id'])
        if manager_chain is None:
            return employee_dict[emp_id]['name']
        return f"{manager_chain} > {employee_dict[emp_id]['name']}"

    manager_chains = {}
    for emp_id in employee_dict:
        manager_chains[emp_id] = build_manager_chain(emp_id)

    # Prepare output
    hierarchy_levels_output = []
    subordinate_count_output = []
    manager_chain_output = []

    for emp_id in employee_dict:
        hierarchy_levels_output.append({
            'employee_id': emp_id,
            'employee_name': employee_dict[emp_id]['name'],
            'level': levels[emp_id]
        })
        subordinate_count_output.append({
            'employee_id': emp_id,
            'employee_name': employee_dict[emp_id]['name'],
            'subordinate_count': subordinate_counts[emp_id]
        })
        manager_chain_output.append({
            'employee_id': emp_id,
            'employee_name': employee_dict[emp_id]['name'],
            'manager_chain': manager_chains[emp_id]
        })

    return hierarchy_levels_output, subordinate_count_output, manager_chain_output

