    def __init__(self, employee_id, employee_name, manager_id):
        self.employee_id = employee_id
        self.employee_name = employee_name
        self.manager_id = manager_id
        self.subordinates = []

def build_hierarchy(employees):
    employee_dict = {emp.employee_id: emp for emp in employees}
    ceo = None

    for emp in employees:
        if emp.manager_id is None:
            ceo = emp
        else:
            manager = employee_dict.get(emp.manager_id)
            if manager:
                manager.subordinates.append(emp)

    return ceo

def calculate_levels(ceo):
    levels = {}
    def dfs(emp, level):
        levels[emp.employee_id] = level
        for sub in emp.subordinates:
            dfs(sub, level + 1)

    dfs(ceo, 1)
    return levels

def count_subordinates(emp):
    count = len(emp.subordinates)
    for sub in emp.subordinates:
        count += count_subordinates(sub)
    return count

def calculate_subordinate_counts(employees):
    subordinate_counts = {}
    for emp in employees:
        subordinate_counts[emp.employee_id] = count_subordinates(emp)
    return subordinate_counts

def build_manager_chain(emp, employee_dict):
    chain = []
    while emp.manager_id is not None:
        emp = employee_dict[emp.manager_id]
        chain.append(emp.employee_name)
    return ' > '.join(reversed(chain)) if chain else None

def calculate_manager_chains(employees):
    employee_dict = {emp.employee_id: emp for emp in employees}
    manager_chains = {}
    for emp in employees:
        manager_chains[emp.employee_id] = build_manager_chain(emp, employee_dict)
    return manager_chains

