    'manager_id': [None, 1, 1, 2, 2, 3]
}

# Create DataFrame
df = pd.DataFrame(data)

# Function to determine hierarchy levels
def determine_levels(df):
    levels = {}
    def get_level(emp_id, current_level):
        if emp_id in levels:
            return levels[emp_id]
        levels[emp_id] = current_level
        manager_id = df.loc[df['employee_id'] == emp_id, 'manager_id'].values[0]
        if pd.isna(manager_id):
            return current_level
        return get_level(manager_id, current_level + 1)

    for emp_id in df['employee_id']:
        get_level(emp_id, 1)

    return levels

# Function to count subordinates
def count_subordinates(df):
    sub_count = {}
    for emp_id in df['employee_id']:
        sub_count[emp_id] = df[df['manager_id'] == emp_id].shape[0] + sum(df[df['manager_id'] == emp_id]['employee_id'].isin(sub_count.keys()))
    return sub_count

# Function to list management chain
def management_chain(df):
    chains = {}
    for emp_id in df['employee_id']:
        chain = []
        current_id = emp_id
        while current_id is not None:
            chain.append(current_id)
            current_id = df.loc[df['employee_id'] == current_id, 'manager_id'].values[0]
        chains[emp_id] = ' > '.join(map(str, chain[::-1]))
    return chains

