def analyze_organization(employees):
    hierarchy_levels = []
    subordinate_counts = []
    manager_chains = {}

    # Create a mapping of employee_id to employee details
    employee_map = {emp['employee_id']: emp for emp in employees}

    # Determine levels and subordinate counts
    for emp in employees:
        level = 1
        current_manager_id = emp['manager_id']
        subordinates = 0

        # Calculate level
        while current_manager_id is not None:
            level += 1
            current_manager_id = employee_map[current_manager_id]['manager_id']

        hierarchy_levels.append({
            'employee_id': emp['employee_id'],
            'employee_name': emp['employee_name'],
            'level': level
        })

        # Count subordinates
        for other_emp in employees:
            if other_emp['manager_id'] == emp['employee_id']:
                subordinates += 1

        subordinate_counts.append({
            'employee_id': emp['employee_id'],
            'employee_name': emp['employee_name'],
            'subordinate_count': subordinates
        })

        # Build manager chain
        chain = []
        current_id = emp['employee_id']
        while current_id is not None:
            chain.append(employee_map[current_id]['employee_name'])
            current_id = employee_map[current_id]['manager_id']
        manager_chains[emp['employee_id']] = ' > '.join(reversed(chain))

    return {
        'hierarchy_levels': hierarchy_levels,
        'subordinate_counts': subordinate_counts,
        'manager_chains': manager_chains
    }

